const raw = $input.first().json;
const text = raw.text ?? '';
const tags = raw.tags ?? [];
const threadParentUri = raw.thread_parent_uri ?? null;
if (!text) throw new Error('Skill Bluesky: text is required');
// Bluesky post limit: 300 grapheme clusters
const truncated = [...text].length > 280 ? [...text].slice(0, 277).join('') + '...' : text;
// Append hashtags if they fit
const tagStr = tags.map(t => '#' + t.replace(/\s+/g, '')).join(' ');
const finalText = (truncated + (tagStr ? ' ' + tagStr : '')).slice(0, 300);
return [{ json: { text: finalText, thread_parent_uri: threadParentUri } }];

const result = $input.item.json;
const uri = result.uri ?? null;
return [{ json: { status: uri ? 'success' : 'failed', post_uri: uri, result_summary: uri ? `Posted to Bluesky: ${uri}` : 'Bluesky post failed' } }];
